// src/hooks/useOversight.ts
import { useState as useState5, useCallback } from "react";
function useOversight(initialMode = "checkpoint") {
  const [mode, setMode] = useState5(initialMode);
  const [queue, setQueue] = useState5([]);
  const [history, setHistory] = useState5([]);
  const requestApproval = useCallback(
    async (payload) => {
      if (mode === "shadow") {
        if (payload.confidence >= 0.8 && payload.risk !== "critical") {
          return true;
        }
      }
      if (mode === "recovery") {
        return false;
      }
      return new Promise((resolve) => {
        setQueue((prev) => [...prev, payload]);
        const checkInterval = setInterval(() => {
          setQueue((current) => {
            const item = current.find(
              (q) => q.action === payload.action && q.agent === payload.agent
            );
            if (!item) {
              clearInterval(checkInterval);
              setHistory((h) => [
                ...h,
                { ...payload, status: "approved", timestamp: (/* @__PURE__ */ new Date()).toISOString() }
              ]);
              resolve(true);
              return current;
            }
            return current;
          });
        }, 500);
      });
    },
    [mode]
  );
  const approve = useCallback((action, agent) => {
    setQueue((prev) => {
      const item = prev.find((q) => q.action === action && q.agent === agent);
      if (item) {
        setHistory((h) => [
          ...h,
          { ...item, status: "approved", timestamp: (/* @__PURE__ */ new Date()).toISOString() }
        ]);
      }
      return prev.filter((q) => !(q.action === action && q.agent === agent));
    });
  }, []);
  const reject = useCallback((action, agent) => {
    setQueue((prev) => {
      const item = prev.find((q) => q.action === action && q.agent === agent);
      if (item) {
        setHistory((h) => [
          ...h,
          { ...item, status: "rejected", timestamp: (/* @__PURE__ */ new Date()).toISOString() }
        ]);
      }
      return prev.filter((q) => !(q.action === action && q.agent === agent));
    });
  }, []);
  const state = {
    mode,
    pendingCount: queue.length,
    approvedCount: history.filter((h) => h.status === "approved").length,
    rejectedCount: history.filter((h) => h.status === "rejected").length
  };
  return {
    mode,
    setMode,
    queue,
    history,
    state,
    requestApproval,
    approve,
    reject
  };
}
